<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('doctor'); require_once __DIR__.'/../../backend/shared/layout.php';
$conditions=['เบาหวานชนิดที่ 1','เบาหวานชนิดที่ 2','เบาหวานขณะตั้งครรภ์','ความดันโลหิตสูง','ไขมันในเลือดสูง','โรคไตเรื้อรัง','โรคหัวใจ','หอบหืด','ICU/ใช้เครื่องช่วยหายใจ','ไม่มีโรคประจำตัว'];
if($_SERVER['REQUEST_METHOD']==='POST'){
  $pdo=db(); $pdo->beginTransaction();
  $hn=$_POST['hn'] ?: 'HN'.date('His'); $height=(float)$_POST['height']; $weight=(float)$_POST['weight']; $bmi=$height>0?round($weight/(($height/100)**2),1):0;
  $st=$pdo->prepare('INSERT INTO patients(hn,citizen_id,first_name,last_name,sex,birthdate,age,weight,height,bmi,blood_type,phone,address,allergy,menstrual_history,pregnancy_history,abortion_history,sexual_history) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)');
  $st->execute([$hn,$_POST['citizen_id'],$_POST['first_name'],$_POST['last_name'],$_POST['sex'],$_POST['birthdate'],$_POST['age'],$weight,$height,$bmi,$_POST['blood_type'],$_POST['phone'],$_POST['address'],$_POST['allergy'],$_POST['menstrual_history'],$_POST['pregnancy_history'],$_POST['abortion_history'],$_POST['sexual_history']]);
  $pid=$pdo->lastInsertId(); $hash=password_hash($_POST['patient_password'] ?: '123456', PASSWORD_DEFAULT); $pdo->prepare('INSERT INTO patient_accounts(patient_id,password_hash) VALUES(?,?)')->execute([$pid,$hash]);
  foreach(($_POST['conditions']??[]) as $c){$pdo->prepare('INSERT INTO patient_conditions(patient_id,condition_name,note) VALUES(?,?,?)')->execute([$pid,$c,$_POST['condition_note']??'']);}
  if(trim($_POST['initial_hba1c']??'')!=='' || trim($_POST['initial_fpg']??'')!=='' || trim($_POST['initial_sbp']??'')!=='' || trim($_POST['initial_dbp']??'')!==''){
    $pdo->prepare('INSERT INTO visits(patient_id,visit_date,hospital_name,visit_type,department,ward,doctor_name,chief_complaint,diagnosis,symptom_note,sbp,dbp,created_by) VALUES(?,?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$pid,date('Y-m-d'),'USE MED Hospital','OPD','ลงทะเบียน/คัดกรอง','OPD',($_SESSION['user']['name']??''),'ลงทะเบียนคนไข้ใหม่และคัดกรองโรค',implode(', ', $_POST['conditions']??[]),$_POST['condition_note']??'',$_POST['initial_sbp'] ?: null,$_POST['initial_dbp'] ?: null,$_SESSION['user']['id']]);
    $vid=$pdo->lastInsertId();
    $pdo->prepare('INSERT INTO diabetes_followups(patient_id,visit_id,followup_date,diabetes_type,hba1c,fpg,sbp,dbp,bmi,egfr,uacr,note) VALUES(?,?,?,?,?,?,?,?,?,?,?,?)')->execute([$pid,$vid,date('Y-m-d'),$_POST['initial_diabetes_type']??'Unknown',$_POST['initial_hba1c'] ?: null,$_POST['initial_fpg'] ?: null,$_POST['initial_sbp'] ?: null,$_POST['initial_dbp'] ?: null,$bmi,$_POST['initial_egfr'] ?: null,$_POST['initial_uacr'] ?: null,'ค่าเริ่มต้นจากการลงทะเบียน']);
  }
  $pdo->commit(); header('Location: patient-profile.php?hn='.urlencode($hn)); exit;
}
app_header('ลงทะเบียนข้อมูลคนไข้ใหม่','doctor','register'); ?>
