r 1fr;gap:8px"><input name="initial_sbp" type="number" placeholder="SBP"><input name="initial_dbp" type="number" placeholder="DBP"></div></div><div class="clinical-card"><strong>BMI</strong><small>คำนวณจากน้ำหนัก/ส่วนสูงอัตโนมัติ</small></div></div><div class="row"><div class="field"><label>ชนิดเบาหวาน</label><select name="initial_diabetes_type"><option>Unknown</option><option>Type 2</option><option>Type 1</option><option>GDM</option></select></div><div class="field"><label>eGFR</label><input name="initial_egfr" type="number" step="0.1"></div><div class="field"><label>UACR</label><input name="initial_uacr" type="number" step="0.1"></div></div></div><div class="row"><div class="field"><label>แพ้ยา</label><textarea name="allergy"></textarea></div><div class="field"><label>ที่อยู่</label><textarea name="address"></textarea></div><div class="field"><label>ประวัติรอบเดือน</label><textarea name="menstrual_history"></textarea></div><div class="field"><label>ประวัติการตั้งครรภ์</label><textarea name="pregnancy_history"></textarea></div><div class="field"><label>แท้ง/ทำแท้ง</label><textarea name="abortion_history"></textarea></div><div class="field"><label>ประวัติการมีเพศสัมพันธ์</label><textarea name="sexual_history"></textarea></div></div><div class="field"><label>หมายเหตุโรค</label><textarea name="condition_note"></textarea></div><button class="btn">บันทึกคนไข้ใหม่ลงฐานข้อมูล</button></form></div><?php app_footer(); ?>
